import React, { useState, useEffect, useRef } from 'react';
import { Send, Lightbulb, AlertCircle, CheckCircle, Target } from 'lucide-react';

const TRANSLATIONS = {
  "en-US": {
    "title": "5 Whys",
    "subtitle": "Answer \"why\" five times and work with Claude to discover the root cause, solutions, and insights.",
    "defineProblem": "Define your problem",
    "whatChallenge": "What challenge are you facing?",
    "procrastinationHabits": "Procrastination habits",
    "lowProductInterest": "Low product interest",
    "familyConflicts": "Family conflicts",
    "codeQualityIssues": "Code quality issues",
    "chronicExhaustion": "Chronic exhaustion",
    "startJourney": "Start journey",
    "whyNumber": "Why #",
    "whyHappen": "Why does \"{problem}\" happen?",
    "whyOccur": "Why does \"{answer}\" occur?",
    "enterAnswer": "Enter your answer...",
    "next": "Next",
    "analyze": "Analyze",
    "analyzingResponses": "Analyzing your responses...",
    "discoveryComplete": "Discovery complete!",
    "foundAtRoot": "Here's what we found at the root of your challenge",
    "rootCause": "Root cause",
    "solutions": "Solutions",
    "keyInsights": "Key insights",
    "startNewJourney": "Start new journey",
    "procrastinationExample": "I keep procrastinating on important personal projects even though I want to complete them",
    "productLaunchExample": "Our new product launch has received less customer interest than expected",
    "familyConflictExample": "I'm experiencing frequent conflicts with my teenage children about screen time and homework",
    "codeQualityExample": "My team struggles to maintain code quality despite having review processes in place",
    "exhaustionExample": "I feel constantly exhausted despite getting enough sleep and exercising regularly"
  },
  /* LOCALE_PLACEHOLDER_START */
  "es-ES": {
    "title": "5 Por Qués",
    "subtitle": "Responde \"por qué\" cinco veces y trabaja con Claude para descubrir la causa raíz, soluciones e insights.",
    "defineProblem": "Define tu problema",
    "whatChallenge": "¿Qué desafío estás enfrentando?",
    "procrastinationHabits": "Hábitos de procrastinación",
    "lowProductInterest": "Bajo interés del producto",
    "familyConflicts": "Conflictos familiares",
    "codeQualityIssues": "Problemas de calidad del código",
    "chronicExhaustion": "Agotamiento crónico",
    "startJourney": "Comenzar viaje",
    "whyNumber": "Por qué #",
    "whyHappen": "¿Por qué sucede \"{problem}\"?",
    "whyOccur": "¿Por qué ocurre \"{answer}\"?",
    "enterAnswer": "Ingresa tu respuesta...",
    "next": "Siguiente",
    "analyze": "Analizar",
    "analyzingResponses": "Analizando tus respuestas...",
    "discoveryComplete": "¡Descubrimiento completo!",
    "foundAtRoot": "Esto es lo que encontramos en la raíz de tu desafío",
    "rootCause": "Causa raíz",
    "solutions": "Soluciones",
    "keyInsights": "Insights clave",
    "startNewJourney": "Comenzar nuevo viaje",
    "procrastinationExample": "Sigo procrastinando en proyectos personales importantes aunque quiero completarlos",
    "productLaunchExample": "Nuestro lanzamiento de nuevo producto ha recibido menos interés del cliente de lo esperado",
    "familyConflictExample": "Estoy experimentando conflictos frecuentes con mis hijos adolescentes sobre tiempo de pantalla y tareas",
    "codeQualityExample": "Mi equipo lucha por mantener la calidad del código a pesar de tener procesos de revisión",
    "exhaustionExample": "Me siento constantemente agotado a pesar de dormir lo suficiente y hacer ejercicio regularmente"
  }
  /* LOCALE_PLACEHOLDER_END */
};

const appLocale = '{{APP_LOCALE}}';
const browserLocale = navigator.languages?.[0] || navigator.language || 'en-US';
const findMatchingLocale = (locale) => {
  if (TRANSLATIONS[locale]) return locale;
  const lang = locale.split('-')[0];
  const match = Object.keys(TRANSLATIONS).find(key => key.startsWith(lang + '-'));
  return match || 'en-US';
};
const locale = (appLocale !== '{{APP_LOCALE}}') ? findMatchingLocale(appLocale) : findMatchingLocale(browserLocale);
const t = (key) => TRANSLATIONS[locale]?.[key] || TRANSLATIONS['en-US'][key] || key;

const FiveWhysVisualJourney = () => {
  const [problem, setProblem] = useState('');
  const [whys, setWhys] = useState(['', '', '', '', '']);
  const [followUpQuestions, setFollowUpQuestions] = useState(['', '', '', '', '']);
  const [currentStep, setCurrentStep] = useState(0);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [analysis, setAnalysis] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [animateStep, setAnimateStep] = useState(null);
  const [isGeneratingQuestion, setIsGeneratingQuestion] = useState(false);
  const stepRefs = useRef([]);

  useEffect(() => {
    if (animateStep !== null) {
      const timer = setTimeout(() => setAnimateStep(null), 500);
      return () => clearTimeout(timer);
    }
  }, [animateStep]);

  useEffect(() => {
    if (currentStep > 0 && stepRefs.current[currentStep]) {
      stepRefs.current[currentStep].scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [currentStep]);

  const generateFollowUpQuestion = async (stepIndex) => {
    setIsGeneratingQuestion(true);
    try {
      let prompt;
      if (stepIndex === 1) {
        // First why question
        prompt = `You are helping someone analyze a problem using the 5 Whys technique. 

Original problem: "${problem}"

Please create a natural, engaging "why" question that asks why this problem occurs. The question should:
- Start with "Why"
- Be conversational and specific to their situation
- Be more engaging than a generic template
- Stay focused on the "why" format

Respond with only the question, no additional text.`;
      } else {
        // Follow-up questions
        const previousAnswers = whys.slice(0, stepIndex - 1).filter(answer => answer.trim());
        const context = previousAnswers.map((answer, idx) => `Answer ${idx + 1}: "${answer}"`).join('\n');

        prompt = `You are helping someone analyze a problem using the 5 Whys technique. 

Original problem: "${problem}"
${context}

Please create a natural, engaging "why" question that asks why their most recent answer occurs. The question should:
- Start with "Why"
- Be conversational and specific to their response
- Be more engaging than a generic template
- Stay focused on the "why" format

Respond with only the question, no additional text.`;
      }

      const response = await window.claude.complete(prompt);
      const newQuestions = [...followUpQuestions];
      newQuestions[stepIndex - 1] = response.trim();
      setFollowUpQuestions(newQuestions);
    } catch (error) {
      console.error('Error generating follow-up question:', error);
      // Fallback to template
      const newQuestions = [...followUpQuestions];
      if (stepIndex === 1) {
        newQuestions[stepIndex - 1] = t('whyHappen').replace('{problem}', problem);
      } else {
        newQuestions[stepIndex - 1] = t('whyOccur').replace('{answer}', whys[stepIndex - 2]);
      }
      setFollowUpQuestions(newQuestions);
    }
    setIsGeneratingQuestion(false);
  };

  const handleProblemSubmit = async () => {
    if (problem.trim()) {
      setAnimateStep(0);
      setCurrentStep(1);
      // Generate the first follow-up question
      await generateFollowUpQuestion(1);
    }
  };

  const handleWhySubmit = async (index) => {
    if (whys[index].trim()) {
      setAnimateStep(index + 1);
      if (index < 4) {
        setCurrentStep(index + 2);
        // Generate the next follow-up question
        await generateFollowUpQuestion(index + 2);
      } else {
        analyzeResponses();
      }
    }
  };

  const handleKeyPress = (e, submitFunction) => {
    if (e.key === 'Enter') {
      submitFunction();
    }
  };

  const analyzeResponses = async () => {
    setIsAnalyzing(true);
    // Scroll to loading state
    setTimeout(() => {
      if (stepRefs.current['analysis']) {
        stepRefs.current['analysis'].scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    }, 100);

    try {
      const prompt = `Please respond in ${locale} language. Analyze this 5 Whys problem-solving session:

Problem: ${problem}

Why 1: ${whys[0]}
Why 2: ${whys[1]}  
Why 3: ${whys[2]}
Why 4: ${whys[3]}
Why 5: ${whys[4]}

Please provide:
1. A clear identification of the root cause
2. Three actionable solutions to address this root cause
3. Key insights from the analysis

Format your response as JSON with the following structure:
{
  "rootCause": "Description of the root cause",
  "solutions": [
    {"title": "Solution 1", "description": "Detailed description"},
    {"title": "Solution 2", "description": "Detailed description"},
    {"title": "Solution 3", "description": "Detailed description"}
  ],
  "insights": ["Insight 1", "Insight 2", "Insight 3"]
}`;

      const response = await window.claude.complete(prompt);
      const result = JSON.parse(response);
      setAnalysis(result);
      setShowAnalysis(true);
      setAnimateStep('analysis');
    } catch (error) {
      console.error('Error analyzing responses:', error);
      setAnalysis({
        rootCause: "Unable to determine root cause due to an error.",
        solutions: [],
        insights: ["Please try again or review your responses."]
      });
      setShowAnalysis(true);
    }
    setIsAnalyzing(false);
  };

  const getStepStyle = (stepIndex) => {
    const baseStyle = {
      transition: 'all 0.3s ease',
      backgroundColor: currentStep === stepIndex ? '#ffffff' : 
                       currentStep > stepIndex || (stepIndex === 5 && showAnalysis) ? '#f3f4f6' : '#e5e7eb',
      border: `2px solid ${currentStep === stepIndex && !showAnalysis ? '#3F3F47' : 'transparent'}`,
      transform: animateStep === stepIndex ? 'scale(1.02)' : 'scale(1)',
      boxShadow: currentStep === stepIndex && !showAnalysis ? '0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06)' : 'none'
    };
    return baseStyle;
  };

  return (
    <div className="min-h-screen py-12" style={{ backgroundColor: '#CBCADB', fontFamily: 'Inter, sans-serif' }}>
      <div className="max-w-4xl mx-auto">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold mb-3" style={{ color: '#3F3F47' }}>
            {t('title')}
          </h1>
          <p className="text-lg max-w-lg mx-auto" style={{ color: '#3F3F47' }}>
            {t('subtitle')}
          </p>
        </div>

        <div className="relative">
          {/* Visual Flow Diagram */}
          <div className="absolute left-1/2 top-0 bottom-0 w-1 bg-gray-300 transform -translate-x-1/2" style={{ height: 'calc(100% - 100px)' }}></div>

          {/* Problem Step */}
          <div className="relative mb-8" ref={el => stepRefs.current[0] = el}>
            <div 
              className="max-w-2xl mx-auto rounded-xl p-6 relative z-10"
              style={getStepStyle(0)}
            >
              <div className="flex items-center gap-3 mb-4">
                <Target className="w-6 h-6" style={{ color: '#3F3F47' }} />
                <h2 className="text-xl font-bold" style={{ color: '#3F3F47' }}>
                  {t('defineProblem')}
                </h2>
              </div>

              {currentStep === 0 ? (
                <div>
                  <textarea
                    value={problem}
                    onChange={(e) => setProblem(e.target.value)}
                    onKeyPress={(e) => {
                      if (e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        handleProblemSubmit();
                      }
                    }}
                    className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-2 mb-4 resize-none"
                    style={{ borderColor: '#3F3F47', minHeight: '80px' }}
                    placeholder={t('whatChallenge')}
                    rows={2}
                  />
                  <div className="mb-4">
                    <div className="flex flex-wrap gap-2">
                      <button
                        onClick={() => setProblem(t('procrastinationExample'))}
                        className="px-3 py-1 text-sm rounded-full border hover:bg-gray-100 transition-colors"
                        style={{ borderColor: '#3F3F47', color: '#3F3F47' }}
                      >
                        {t('procrastinationHabits')}
                      </button>
                      <button
                        onClick={() => setProblem(t('productLaunchExample'))}
                        className="px-3 py-1 text-sm rounded-full border hover:bg-gray-100 transition-colors"
                        style={{ borderColor: '#3F3F47', color: '#3F3F47' }}
                      >
                        {t('lowProductInterest')}
                      </button>
                      <button
                        onClick={() => setProblem(t('familyConflictExample'))}
                        className="px-3 py-1 text-sm rounded-full border hover:bg-gray-100 transition-colors"
                        style={{ borderColor: '#3F3F47', color: '#3F3F47' }}
                      >
                        {t('familyConflicts')}
                      </button>
                      <button
                        onClick={() => setProblem(t('codeQualityExample'))}
                        className="px-3 py-1 text-sm rounded-full border hover:bg-gray-100 transition-colors"
                        style={{ borderColor: '#3F3F47', color: '#3F3F47' }}
                      >
                        {t('codeQualityIssues')}
                      </button>
                      <button
                        onClick={() => setProblem(t('exhaustionExample'))}
                        className="px-3 py-1 text-sm rounded-full border hover:bg-gray-100 transition-colors"
                        style={{ borderColor: '#3F3F47', color: '#3F3F47' }}
                      >
                        {t('chronicExhaustion')}
                      </button>
                    </div>
                  </div>
                  <button
                    onClick={handleProblemSubmit}
                    className="w-full px-6 py-3 rounded-lg text-white flex items-center justify-center gap-2 hover:opacity-90 transition-all"
                    style={{ backgroundColor: '#3F3F47' }}
                    disabled={!problem.trim()}
                  >
                    {t('startJourney')}
                  </button>
                </div>
              ) : (
                <p style={{ color: '#3F3F47' }}>{problem}</p>
              )}
            </div>
          </div>

          {/* Why Steps */}
          {[1, 2, 3, 4, 5].map((num) => (
            <div key={num} className="relative mb-8" ref={el => stepRefs.current[num] = el}>
              {currentStep >= num && (
                <div 
                  className="max-w-2xl mx-auto rounded-xl p-6 relative z-10"
                  style={getStepStyle(num)}
                >
                  <div className="flex items-center gap-3 mb-4">
                    <div className="w-6 h-6 rounded-full flex items-center justify-center font-bold text-white text-sm" 
                         style={{ backgroundColor: '#3F3F47' }}>
                      {num}
                    </div>
                    <h2 className="text-xl font-bold" style={{ color: '#3F3F47' }}>
                      {t('whyNumber')}{num}
                    </h2>
                  </div>

                  {currentStep === num ? (
                    <div>
                      {isGeneratingQuestion ? (
                        <div className="mb-3 flex items-center gap-2">
                          <div className="flex">
                            <div className="w-1 h-1 rounded-full bg-gray-400 animate-bounce mx-0.5" style={{ animationDelay: '0ms' }}></div>
                            <div className="w-1 h-1 rounded-full bg-gray-400 animate-bounce mx-0.5" style={{ animationDelay: '150ms' }}></div>
                            <div className="w-1 h-1 rounded-full bg-gray-400 animate-bounce mx-0.5" style={{ animationDelay: '300ms' }}></div>
                          </div>
                          <span className="text-sm" style={{ color: '#3F3F47' }}>Thinking...</span>
                        </div>
                      ) : (
                        <p className="mb-3 text-sm" style={{ color: '#3F3F47' }}>
                          {followUpQuestions[num - 1] || 
                           (num === 1 ? t('whyHappen').replace('{problem}', problem) : 
                            t('whyOccur').replace('{answer}', whys[num - 2]))}
                        </p>
                      )}
                      <div className="flex gap-2">
                        <input
                          type="text"
                          value={whys[num - 1]}
                          onChange={(e) => {
                            const newWhys = [...whys];
                            newWhys[num - 1] = e.target.value;
                            setWhys(newWhys);
                          }}
                          onKeyPress={(e) => handleKeyPress(e, () => handleWhySubmit(num - 1))}
                          className="flex-1 px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-2"
                          style={{ borderColor: '#3F3F47' }}
                          placeholder={t('enterAnswer')}
                        />
                        <button
                          onClick={() => handleWhySubmit(num - 1)}
                          className="px-4 py-3 rounded-lg text-white flex items-center gap-2 hover:opacity-90 transition-all disabled:opacity-50"
                          style={{ backgroundColor: '#3F3F47' }}
                          disabled={!whys[num - 1].trim() || isGeneratingQuestion}
                        >
                          {num === 5 ? t('analyze') : t('next')}
                          <Send className="w-4 h-4" />
                        </button>
                      </div>
                    </div>
                  ) : currentStep > num ? (
                    <p style={{ color: '#3F3F47' }}>{whys[num - 1]}</p>
                  ) : null}
                </div>
              )}
            </div>
          ))}

          {/* Analysis Loading */}
          {isAnalyzing && (
            <div className="text-center py-12" ref={el => stepRefs.current['analysis'] = el}>
              <div className="flex justify-center mb-4">
                <div className="w-2 h-2 rounded-full bg-gray-600 animate-bounce mx-1" style={{ animationDelay: '0ms' }}></div>
                <div className="w-2 h-2 rounded-full bg-gray-600 animate-bounce mx-1" style={{ animationDelay: '150ms' }}></div>
                <div className="w-2 h-2 rounded-full bg-gray-600 animate-bounce mx-1" style={{ animationDelay: '300ms' }}></div>
              </div>
              <p className="text-lg" style={{ color: '#3F3F47' }}>
                {t('analyzingResponses')}
              </p>
            </div>
          )}

          {/* Analysis Results */}
          {showAnalysis && analysis && (
            <div 
              className="max-w-2xl mx-auto mt-12 mb-8"
              style={{
                transform: animateStep === 'analysis' ? 'scale(1.02)' : 'scale(1)',
                transition: 'all 0.5s ease'
              }}
              ref={el => stepRefs.current['results'] = el}
            >
              <div className="text-center mb-8">
                <h2 className="text-3xl font-bold mb-2" style={{ color: '#3F3F47' }}>
                  {t('discoveryComplete')}
                </h2>
                <p className="text-lg" style={{ color: '#3F3F47' }}>
                  {t('foundAtRoot')}
                </p>
              </div>

              <div className="space-y-6">
                {/* Root Cause */}
                <div className="bg-white rounded-xl p-6 shadow-lg border-2" style={{ borderColor: '#3F3F47' }}>
                  <div className="flex items-center gap-3 mb-4">
                    <AlertCircle className="w-6 h-6" style={{ color: '#3F3F47' }} />
                    <h3 className="text-xl font-bold" style={{ color: '#3F3F47' }}>{t('rootCause')}</h3>
                  </div>
                  <p style={{ color: '#3F3F47' }}>{analysis.rootCause}</p>
                </div>

                {/* Solutions */}
                <div className="bg-white rounded-xl p-6 shadow-lg">
                  <div className="flex items-center gap-3 mb-6">
                    <Lightbulb className="w-6 h-6" style={{ color: '#3F3F47' }} />
                    <h3 className="text-xl font-bold" style={{ color: '#3F3F47' }}>{t('solutions')}</h3>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {analysis.solutions.map((solution, index) => (
                      <div key={index} className="bg-gray-50 p-4 rounded-lg">
                        <h4 className="font-bold mb-2" style={{ color: '#3F3F47' }}>{solution.title}</h4>
                        <p style={{ color: '#3F3F47' }}>{solution.description}</p>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Insights */}
                <div className="bg-white rounded-xl p-6 shadow-lg">
                  <h3 className="text-xl font-bold mb-4" style={{ color: '#3F3F47' }}>{t('keyInsights')}</h3>
                  <div className="space-y-3">
                    {analysis.insights.map((insight, index) => (
                      <div key={index} className="flex items-start gap-3">
                        <CheckCircle className="w-5 h-5 mt-0.5 flex-shrink-0" style={{ color: '#3F3F47' }} />
                        <p style={{ color: '#3F3F47' }}>{insight}</p>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="text-center mt-8">
                <button
                  onClick={() => {
                    setProblem('');
                    setWhys(['', '', '', '', '']);
                    setFollowUpQuestions(['', '', '', '', '']);
                    setCurrentStep(0);
                    setShowAnalysis(false);
                    setAnalysis(null);
                    setAnimateStep(null);
                  }}
                  className="px-8 py-3 rounded-lg text-white font-semibold hover:opacity-90 transition-all"
                  style={{ backgroundColor: '#3F3F47' }}
                >
                  {t('startNewJourney')}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default FiveWhysVisualJourney;
